mapper.select:
SELECT a.AREA_ID as "areaId", a.REGION_ID as "regionId", a.SEARCH_TYPE as "searchType", a.NAME as "name", a.MAP_X as "mapX", a.MAP_Y as "mapY", a.CATEGORY as "category", a.ADDRESS as "address", a.ROAD_ADDRESS as "roadAddress", a.LINK as "link", a.TELEPHONE as "telephone", a.DESCRIPTION as "description", a.BOOKMARK_COUNT as "bookmarkCount", a.CREATE_DATE as "createDate", a.LATEST_DATE as "latestDate", a.STATUS as "status" FROM AREA a
AND a.REGION_ID = #{regionId}
AND a.SEARCH_TYPE = #{searchType}
AND LOWER(a.NAME) LIKE LOWER('%' || #{keyword} || '%')
ORDER BY a.AREA_ID OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*)
FROM AREA a


        AND a.REGION_ID = #{regionId}


        AND a.SEARCH_TYPE = #{searchType}


        AND LOWER(a.NAME) LIKE LOWER('%' || #{keyword} || '%')

SELECT COUNT(*)
FROM AREA a
WHERE a.REGION_ID IN (
SELECT r.REGION_ID FROM REGION r WHERE r.ZDO_CODE = #{zdoCode}
)

    AND a.SEARCH_TYPE = #{searchType}


    AND LOWER(a.NAME) LIKE LOWER('%' || #{keyword} || '%')
